// math_utils.h
#ifndef MATH_UTILS_H
#define MATH_UTILS_H

int add(int a, int b);
int subtract(int a, int b);

#endif

// math_utils.c
#include "math_utils.h"

int add(int a, int b) {
  return a + b;
}

int subtract(int a, int b) {
  return a - b;
}

// main.c
#include <stdio.h>
#include "math_utils.h"

int main() {
  printf("Sum: %d\n", add(5, 3));
  printf("Difference: %d\n", subtract(5, 3));
  return 0;
}
// Output:
// Sum: 8
// Difference: 2

// config.h
#ifndef CONFIG_H
#define CONFIG_H

#define MAX_SIZE 100
typedef struct {
  int id;
  char name[50];
} User;

#endif

// main.c
#include <stdio.h>
#include "config.h"

int main() {
  User user;
  user.id = 1;
  user.name[0] = 'A';
  user.name[1] = 'l';
  user.name[2] = 'i';
  user.name[3] = '\0';
  printf("User ID: %d, Name: %s, Max Size: %d\n", user.id, user.name, MAX_SIZE);
  return 0;
}
// Output:
// User ID: 1, Name: Ali, Max Size: 100

// types.h
#ifndef TYPES_H
#define TYPES_H

typedef enum {
  Monday,
  Tuesday,
  Wednesday,
  Thursday,
  Friday,
  Saturday,
  Sunday
} Day;

typedef struct {
  int id;
  Day day;
} Event;

#endif

// main.c
#include <stdio.h>
#include "types.h"

int main() {
  Event event;
  event.id = 101;
  event.day = Wednesday;
  printf("Event ID: %d, Day: %d\n", event.id, event.day);
  return 0;
}
// Output:
// Event ID: 101, Day: 2

// bad_header.h
int add(int a, int b); // include guard yoxdur

// main.c
#include <stdio.h>
#include "bad_header.h"
#include "bad_header.h" // Təkrar daxil edilir

int add(int a, int b) {
  return a + b;
}

int main() {
  printf("Sum: %d\n", add(3, 4));
  return 0;
}
// Output: (Kompilyasiya xətası: multiple definition)

